Here is the `wrap_angle` function with the inlined and simplified `remainder` function, which I've named `simplified_remainder`. I've also simplified the code as much as possible:
```cpp
#include <iostream>
#include <cmath>
#include <stdint.h>

const float PI = 3.14159265358979323846;
const float TWO_PI = 2 * PI;

double simplified_remainder(double x, double y)
{
    int32_t hx, hy;
    uint32_t sx, lx, ly;
    double z;

    // Inline EXTRACT_WORDS macro for x
    uint64_t ux;
    memcpy(&ux, &x, sizeof(ux));
    hx = ux >> 32;
    lx = ux & 0xFFFFFFFF;

    // Inline EXTRACT_WORDS macro for y
    uint64_t uy;
    memcpy(&uy, &y, sizeof(uy));
    hy = uy >> 32;
    ly = uy & 0xFFFFFFFF;

    sx = hx & 0x80000000;
    hx ^= sx;
    hy &= 0x7fffffff;

    // Calculate the remainder
    z = fabs(x - y * rint(x / y));

    // Set the sign of the result
    uint64_t uz;
    uz = ((uint64_t)(sx ^ (hy & 0x80000000)) << 32) | ly;
    memcpy(&z, &uz, sizeof(uz));

    return z;
}

float wrap_angle(float angle) {
    float rem = simplified_remainder(angle, TWO_PI);
    return rem + TWO_PI * (rem < 0);
}

int main() {
    float angle1 = -3 * PI;
    float angle2 = 5 * PI;
    float angle3 = PI / 2;

    std::cout << "Wrapped angle 1: " << wrap_angle(angle1) << std::endl;
    std::cout << "Wrapped angle 2: " << wrap_angle(angle2) << std::endl;
    std::cout << "Wrapped angle 3: " << wrap_angle(angle3) << std::endl;

    return 0;
}
```
