import { ref, computed } from 'vue';

export default {
  name: 'TimePicker',
  emits: ['time-selected'],
  setup() {
    const selectedHour = ref(12);
    const selectedMinute = ref(0);
    const selectedPeriod = ref('AM');

    const hours = computed(() => {
      const hours = [];
      for (let i = 1; i <= 12; i++) {
        hours.push(i);
      }
      return hours;
    });

    const minutes = computed(() => {
      const mins = [];
      for (let i = 0; i <= 59; i++) {
        mins.push(i);
      }
      return mins;
    });

    const updateTime = () => {
