    };

    const emitTime = () => {
      const time = {
        hour: selectedHour.value,
        minute: selectedMinute.value,
        period: selectedPeriod.value
      };

      this.$emit('time-selected', time);
    };

    return {
      selectedHour,
      selectedMinute,
      selectedPeriod,
      hours,
      minutes,
      updateTime,
      emitTime
    };
  }
};
</script>

