import React, { useState, useEffect } from 'react';
import './App.css';

function App() {
  const [localStream, setLocalStream] = useState(null);
  const [remoteStream, setRemoteStream] = useState(null);
  const [socket, setSocket] = useState(null);

  useEffect(() => {
    const socket = new WebSocket('ws://localhost:8080');

    socket.onopen = () => {
      console.log('WebSocket connected');
      navigator.mediaDevices.getUserMedia({ video: true, audio: true })
        .then(stream => {
          setLocalStream(stream);
          const video = document.getElementById('localVideo');
          video.srcObject = stream;
        });
    };

    socket.onmessage = async (event) => {
      const message = JSON.parse(event.data);
      if (message.sdp) {
        const remotePeer = new RTCPeerConnection();
        remotePeer.setRemoteDescription(new RTCSessionDescription(message.sdp));
        remotePeer.onicecandidate = (event) => {
          if (event.candidate) {
            socket.send(JSON.stringify({ ice: event.candidate }));
          }
        };
        remotePeer.ontrack = (event) => {
          const remoteVideo = document.getElementById('remoteVideo');
          remoteVideo.srcObject = event.streams[0];
        };
        const answer = await remotePeer.createAnswer();
        await remotePeer.setLocalDescription(answer);
        socket.send(JSON.stringify({ sdp: answer }));
      } else if (message.ice) {
        const remotePeer = new RTCPeerConnection();
        remotePeer.addIceCandidate(new RTCIceCandidate(message.ice));
      }
    };

    setSocket(socket);

    return () => {
      socket.close();
    };
  }, []);

