To update the CSV file with the **last successful recording imported** for each user, you can:

- Keep track of the last successful recording date for each user.
- After successfully importing a recording, update the CSV with the latest date.

Below is the **updated PHP code** that includes this functionality:

---

### ✅ Updated PHP Code Snippet

```php
<?php

// Load AWS SDK for PHP
require 'vendor/autoload.php';

use Aws\S3\S3Client;

// Set AWS access keys
$accessKey = 'ACCESS_KEY';
$secretKey = 'SECRET_KEY';

// Set S3 bucket and region
$bucket = 'BUCKET_NAME';
$region = 'REGION';

// Create an S3 client
$s3 = new S3Client([
    'version' => 'latest',
    'region'  => $region,
    'credentials' => [
        'key' => $accessKey,
        'secret' => $secretKey
    ]
]);

// Load Microsoft Graph SDK
require 'vendor/autoload.php';

use Microsoft\Graph\Graph;
use Microsoft\Graph\Model;

// Set Graph API credentials
$clientId = 'CLIENT_ID';
$clientSecret = 'CLIENT_SECRET';
$tenantId = 'TENANT_ID';

// Read the CSV file
$csvFile = file('users.csv');

// Store the last successful import date for each user
$lastSuccessfulImports = [];

// Loop through the rows of the CSV file
foreach ($csvFile as $row) {
    // Get the user's email, last import date, and last recording ID (optional)
    list($email, $lastImportDate) = str_getcsv($row);

    // Initialize Graph client
    $graph = new Graph();
    $graph->setAccessToken(getAccessToken($clientId, $clientSecret, $tenantId));

    // Get the user's events
    try {
        $events = $graph->createRequest('GET', '/users/' . $email . '/events')
            ->setReturnType(Model\Event::class)
            ->execute();

        // Loop through the events
        foreach ($events as $event) {
            // Check if the event has a recording and was created after the last import date
            if ($event->getHasRecording() && $event->getCreatedDateTime() > $lastImportDate) {
                // Get the recording URL
                $recordingUrl = $event->getExtensions()['com.microsoft.graph.legacyRecordings'][0]['contentUrl'];

                // Download the recording from Microsoft Teams
                $recordingData = file_get_contents($recordingUrl);

                // Generate a unique filename for the recording
                $filename = uniqid() . '.mp4';

                // Upload the recording to S3
                $s3->putObject([
                    'Bucket' => $bucket,
                    'Key' => $filename,
                    'Body' => $recordingData,
                    'ACL' => 'public-read'
                ]);

                // Save the last successful import date
                $lastSuccessfulImports[$email] = $event->getCreatedDateTime()->format('Y-m-d H:i:s');
            }
        }
    } catch (Exception $e) {
        error_log("Error retrieving events for user $email: " . $e->getMessage());
    }
}

// Update the CSV with the last successful import date
updateCsvWithLastImports($csvFile, $lastSuccessfulImports);

// Helper function to get access token
function getAccessToken($clientId, $clientSecret, $tenantId) {
    $authUrl = 'https://login.microsoftonline.com/' . $tenantId . '/oauth2/v2.0/token';
    $data = [
        'grant_type' => 'client_credentials',
        'client_id' => $clientId,
        'client_secret' => $clientSecret,
        'scope' => 'https://graph.microsoft.com/.default'
    ];

    $options = [
        'http' => [
            'header' => "Content-type: application/x-www-form-urlencoded\r\n",
            'method' => 'POST',
            'content' => http_build_query($data)
        ]
    ];

    $context = stream_context_create($options);
    $result = file_get_contents($authUrl, false, $context);
    $response = json_decode($result);
    return $response->access_token;
}

// Helper function to update CSV
function updateCsvWithLastImports($originalCsv, $lastImports) {
    $fileContents = [];

    foreach ($originalCsv as $row) {
        list($email, $lastImportDate) = str_getcsv($row);
        $newLastImportDate = isset($lastImports[$email]) ? $lastImports[$email] : $lastImportDate;
        $fileContents[] = "$email,$newLastImportDate";
    }

    // Write the updated CSV
    file_put_contents('users.csv', implode("\n", $fileContents));
}
?>
