```cpp
#include <iostream>
#include <chrono>
#include <thread>
#include <functional>
#include <stdexcept>

class CircuitBreaker {
public:
    enum class State { CLOSED, OPEN, HALF_OPEN };

    CircuitBreaker(unsigned int max_failures, std::chrono::milliseconds timeout)
        : max_failures_(max_failures), timeout_(timeout), failure_count_(0), state_(State::CLOSED) {}

    template <typename T>
    T call(std::function<T()> function) {
        switch (state_) {
            case State::CLOSED:
                try {
                    T result = function();
                    reset_failures();
                    return result;
                } catch (const std::exception& e) {
                    increment_failures();
                    if (failure_count_ >= max_failures_) {
                        open_circuit();
                    }
                    throw e;
                }
            case State::OPEN:
                if (std::chrono::steady_clock::now() >= open_until_) {
                    half_open_circuit();
                }
                throw std::runtime_error("Circuit is open");
            case State::HALF_OPEN:
                try {
                    T result = function();
                    close_circuit();
                    return result;
                } catch (const std::exception& e) {
                    open_circuit();
                    throw e;
                }
        }
    }

    State get_state() const {
        return state_;
    }

private:
    unsigned int max_failures_;
    std::chrono::milliseconds timeout_;
    unsigned int failure_count_;
    State state_;
    std::chrono::steady_clock::time_point open_until_;

    void reset_failures() {
        failure_count_ = 0;
    }

    void increment_failures() {
        ++failure_count_;
    }

    void open_circuit() {
        state_ = State::OPEN;
        open_until_ = std::chrono::steady_clock::now() + timeout_;
    }

    void close_circuit() {
        state_ = State::CLOSED;
        reset_failures();
    }

    void half_open_circuit() {
        state_ = State::HALF_OPEN;
    }
};
```
