## 📁 File: `CircuitBreaker.h`

```cpp
#ifndef CIRCUIT_BREAKER_H
#define CIRCUIT_BREAKER_H

#include <atomic>
#include <mutex>
#include <chrono>
#include <functional>
#include <stdexcept>
#include <type_traits>

namespace circuit_breaker {

template <typename FailureType>
class CircuitBreaker {
public:
    using FailureCallback = std::function<void(const FailureType&)>;

    CircuitBreaker(unsigned max_failures = 3, 
                  unsigned reset_timeout = 30, 
                  const FailureCallback& on_failure = nullptr)
        : max_failures_(max_failures),
          reset_timeout_(reset_timeout),
          on_failure_(on_failure),
          state_(State::CLOSED),
          failure_count_(0),
          last_failure_time_(std::chrono::steady_clock::now()) {}

    ~CircuitBreaker() = default;

    // Disallow copy
    CircuitBreaker(const CircuitBreaker&) = delete;
    CircuitBreaker& operator=(const CircuitBreaker&) = delete;

    // Allow move
    CircuitBreaker(CircuitBreaker&&) = default;
    CircuitBreaker& operator=(CircuitBreaker&&) = default;

    template <typename Func>
    auto execute(Func&& func) -> decltype(func()) {
        std::lock_guard<std::mutex> lock(mutex_);

        if (state_ == State::OPEN) {
            throw std::runtime_error("Circuit breaker is open");
        }

        try {
            if (state_ == State::HALF_OPEN) {
                // If in half-open, just try the function once
                return func();
            }

            // Try the function
            return func();
        } catch (const FailureType& e) {
            if (on_failure_) {
                on_failure_(e);
            }

            // Update failure count and state
            failure_count_++;
            last_failure_time_ = std::chrono::steady_clock::now();

            if (failure_count_ >= max_failures_) {
                state_ = State::OPEN;
            }

            throw std::runtime_error("Operation failed, circuit breaker tripped");
        } catch (...) {
            throw;
        }
    }

    void reset() {
        std::lock_guard<std::mutex> lock(mutex_);
        state_ = State::CLOSED;
        failure_count_ = 0;
        last_failure_time_ = std::chrono::steady_clock::now();
    }

    bool is_open() const {
        std::lock_guard<std::mutex> lock(mutex_);
        return state_ == State::OPEN;
    }

    bool is_half_open() const {
        std::lock_guard<std::mutex> lock(mutex_);
        return state_ == State::HALF_OPEN;
    }

    bool is_closed() const {
        std::lock_guard<std::mutex> lock(mutex_);
        return state_ == State::CLOSED;
    }

    void check_and_transition() {
        std::lock_guard<std::mutex> lock(mutex_);

        if (state_ == State::OPEN) {
            auto now = std::chrono::steady_clock::now();
            auto elapsed = std::chrono::duration_cast<std::chrono::seconds>(now - last_failure_time_).count();

            if (elapsed >= reset_timeout_) {
                state_ = State::HALF_OPEN;
            }
        }
    }

private:
    enum class State {
        CLOSED,
        OPEN,
        HALF_OPEN
    };

    unsigned max_failures_;
    unsigned reset_timeout_;
    FailureCallback on_failure_;
    std::atomic<State> state_;
    std::atomic<unsigned> failure_count_;
    std::atomic<std::chrono::steady_clock::time_point> last_failure_time_;
    mutable std::mutex mutex_;
};

} // namespace circuit_breaker
```

