// Define a failure type (can be any type, e.g., std::exception, custom type)
struct MyFailure {
    std::string message;
};

// Function that may fail
int do_work() {
    static int failure_count = 0;
    failure_count++;
    if (failure_count < 3) {
        throw MyFailure{"Too many failures"};
    }
    std::cout << "Work done successfully" << std::endl;
    return 42;
}

// Failure callback
void on_failure(const MyFailure& e) {
    std::cerr << "Circuit breaker failed: " << e.message << std::endl;
}

int main() {
    using namespace circuit_breaker;

    CircuitBreaker<MyFailure> breaker(3, 5, on_failure);

    try {
        for (int i = 0; i < 10; ++i) {
            std::cout << "Attempt " << i + 1 << ": ";
            breaker.check_and_transition();
            auto result = breaker.execute([&] { return do_work(); });
            std::cout << "Success: " << result << std::endl;
        }
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << std::endl;
    }

    return 0;
}
